170→fn detect_file_type(path: &std::path::Path) -> &'static str {
171→    if path.is_dir() {
172→        return "folder";
173→    }
174→
175→    match path
176→        .extension()
177→        .and_then(|e| e.to_str())
178→        .map(|e| e.to_lowercase())
179→        .as_deref()
180→    {
181→        Some(
182→            "ts" | "tsx" | "js" | "jsx" | "rs" | "py" | "rb" | "go" | "java" | "c" | "cpp" | "h"
183→            | "hpp" | "cs" | "swift" | "kt" | "scala" | "sh" | "bash" | "zsh" | "json" | "yaml"
184→            | "yml" | "toml" | "xml" | "html" | "css" | "scss" | "less" | "sql" | "graphql"
185→            | "proto" | "lua" | "r" | "php" | "pl" | "ex" | "exs" | "erl" | "hs" | "ml"
186→            | "vim" | "el" | "clj" | "dart",
187→        ) => "code",
188→        Some("png" | "jpg" | "jpeg" | "gif" | "bmp" | "svg" | "webp" | "ico" | "tiff" | "avif") => {
189→            "image"
190→        }
191→        Some("pdf") => "pdf",
192→        Some("zip" | "tar" | "gz" | "bz2" | "xz" | "7z" | "rar" | "dmg" | "iso") => "archive",
193→        Some("xlsx" | "xls" | "csv" | "numbers" | "ods") => "spreadsheet",
194→        Some("pptx" | "ppt" | "key" | "odp") => "presentation",
195→        Some(
196→            "md" | "txt" | "rtf" | "doc" | "docx" | "pages" | "odt" | "tex" | "log" | "conf"
197→            | "cfg" | "ini" | "env" | "fig",
198→        ) => "document",
199→        _ => "document",
200→    }
201→}
