231→#[tauri::command(async)]
232→fn search_files(query: String, paths: Vec<String>, max_results: usize) -> Vec<FileEntryResult> {
233→    let max = if max_results == 0 { 200 } else { max_results };
234→    let query_lower = query.to_lowercase();
235→    let mut results: Vec<FileEntryResult> = Vec::new();
236→
237→    let search_paths: Vec<String> = if paths.is_empty() {
238→        if let Some(home) = dirs_next::home_dir() {
239→            let home_str = home.to_string_lossy().to_string();
240→            vec![
241→                format!("{home_str}/Documents"),
242→                format!("{home_str}/Downloads"),
243→                format!("{home_str}/Desktop"),
244→                format!("{home_str}/Projects"),
245→            ]
246→        } else {
247→            return results;
248→        }
249→    } else {
250→        paths
251→    };
252→
253→    for search_path in &search_paths {
254→        if results.len() >= max {
255→            break;
256→        }
257→
258→        let walker = WalkDir::new(search_path)
259→            .max_depth(5)
260→            .follow_links(false)
261→            .into_iter()
262→            .filter_entry(|entry| {
263→                let name = entry.file_name().to_string_lossy();
264→                if name.starts_with('.') && entry.depth() > 0 {
265→                    return false;
266→                }
267→                if entry.file_type().is_dir() && is_ignored_dir(&name) {
268→                    return false;
269→                }
270→                true
271→            });
272→
273→        for entry in walker.flatten() {
274→            if results.len() >= max {
275→                break;
276→            }
277→
278→            let name = entry.file_name().to_string_lossy().to_string();
279→
280→            if !query_lower.is_empty() && !name.to_lowercase().contains(&query_lower) {
281→                continue;
282→            }
283→
284→            if entry.depth() == 0 {
285→                continue;
286→            }
287→
288→            let path = entry.path();
289→            let metadata = match entry.metadata() {
290→                Ok(m) => m,
291→                Err(_) => continue,
292→            };
293→
294→            let size = metadata.len();
295→            let modified_at = metadata
296→                .modified()
297→                .ok()
298→                .and_then(|t| t.duration_since(std::time::UNIX_EPOCH).ok())
299→                .map(|d| d.as_millis() as u64)
300→                .unwrap_or(0);
301→
302→            let file_type = detect_file_type(path);
303→            let path_str = path.to_string_lossy().to_string();
304→
305→            let id = format!("fs-{:x}", {
306→                use std::hash::{Hash, Hasher};
307→                let mut h = std::collections::hash_map::DefaultHasher::new();
308→                path_str.hash(&mut h);
309→                h.finish()
310→            });
311→
312→            results.push(FileEntryResult {
313→                id,
314→                name,
315→                path: path_str,
316→                file_type: file_type.to_string(),
317→                size,
318→                modified_at,
319→            });
320→        }
321→    }
322→
323→    results
324→}
