483→fn extract_app_icon(app_path: &std::path::Path, dict: &plist::Dictionary) -> Option<String> {
484→    let icon_name = dict
485→        .get("CFBundleIconFile")
486→        .and_then(|v| v.as_string())
487→        .unwrap_or("AppIcon");
488→
489→    let icon_filename = if icon_name.ends_with(".icns") {
490→        icon_name.to_string()
491→    } else {
492→        format!("{icon_name}.icns")
493→    };
494→
495→    let icns_path = app_path.join("Contents/Resources").join(&icon_filename);
496→    let icns_data = std::fs::read(&icns_path).ok()?;
497→    let png_data = extract_png_from_icns(&icns_data)?;
498→
499→    Some(format!(
500→        "data:image/png;base64,{}",
501→        base64::engine::general_purpose::STANDARD.encode(&png_data)
502→    ))
503→}
