505→fn build_app_list() -> Vec<AppEntry> {
506→    let mut apps = Vec::new();
507→    let mut seen_paths = std::collections::HashSet::new();
508→
509→    let mut dirs = vec![std::path::PathBuf::from("/Applications")];
510→    if let Some(home) = dirs_next::home_dir() {
511→        dirs.push(home.join("Applications"));
512→    }
513→
514→    for dir in &dirs {
515→        for app_path in scan_app_dir(dir, 1) {
516→            let path_str = app_path.to_string_lossy().to_string();
517→            if !seen_paths.insert(path_str.clone()) {
518→                continue;
519→            }
520→
521→            let file_stem = app_path
522→                .file_stem()
523→                .map(|s| s.to_string_lossy().to_string())
524→                .unwrap_or_default();
525→
526→            let plist_dict = read_info_plist(&app_path);
527→            let name = plist_dict
528→                .as_ref()
529→                .and_then(display_name_from_plist)
530→                .unwrap_or_else(|| file_stem.clone());
531→            let icon = plist_dict
532→                .as_ref()
533→                .and_then(|dict| extract_app_icon(&app_path, dict));
534→
535→            let id = format!("app-{:x}", {
536→                use std::hash::{Hash, Hasher};
537→                let mut h = std::collections::hash_map::DefaultHasher::new();
538→                path_str.hash(&mut h);
539→                h.finish()
540→            });
541→
542→            apps.push(AppEntry {
543→                id,
544→                name,
545→                path: path_str,
546→                icon,
547→            });
548→        }
549→    }
550→
551→    apps.sort_by(|a, b| a.name.to_lowercase().cmp(&b.name.to_lowercase()));
552→    apps
553→}
